};

scwin.RetrieveAccount = async function() {
    ds_Account.removeAll();
    let rowPos = ds_ClntMaster.getRowPosition();
    if (rowPos < 0) return;
    dma_search.set("stype", "ez112Idx");
    dma_search.set("stext", ds_ClntMaster.getCellData(rowPos, "ez112Idx"));
    await $c.sbm.execute(sbm_RetrieveAccount);
};

