scwin.newinput = async function() {
    ds_Account.removeAll();
    ds_FixCost.removeAll();
    ds_ItemFare.removeAll();
    ds_PosFare.removeAll();
    ds_UnionFare.removeAll();
    if (ds_ClntMaster.getRowCount() == 0) {
        ds_ClntMaster.insertRow();
    } else {
        let chk = 0;
        for (let i = 0; i < ds_ClntMaster.getRowCount(); i++) {
            if (ds_ClntMaster.getRowStatus(i) == "C") {
                chk++;
            }
        }
        if (chk > 0) {
            await $c.win.alert("새로운 거래처정보는 저장 후 다시 추가해주세요.");
        } else {
            ds_ClntMaster.insertRow();
        }
    }
};

scwin.addAccount = async function() {
    let rowPos = ds_ClntMaster.getRowPosition();
    if (rowPos < 0) return;
    if (ds_ClntMaster.getRowStatus(rowPos) == "C") {
        await $c.win.alert("거처래정보를 저장하신 후에 입력하실수 있습니다.");
    } else if (ds_Account.getRowCount() > 0 && ds_Account.getCellData(ds_Account.getRowPosition(), "bankCd") == "") {
        await $c.win.alert("은행을 선택해주세요.");
    } else if (ds_Account.getRowCount() > 0 && ds_Account.getCellData(ds_Account.getRowPosition(), "bankAcntNo") == "") {
        await $c.win.alert("계좌번호를 입력해주세요.");
    } else {
        let newIdx = ds_Account.insertRow();
        ds_Account.setCellData(newIdx, "ez112Idx", ds_ClntMaster.getCellData(rowPos, "ez112Idx"));
    }
};

