scwin.deletethis = async function() {
    let chk = await $c.win.confirm("삭제하시겠습니까?");
    if (chk) {
        let rowPos = ds_ClntMaster.getRowPosition();
        if (rowPos < 0) return;
        if (ds_ClntMaster.getRowStatus(rowPos) == "C") {
            ds_ClntMaster.removeRow(rowPos);
        } else {
            dma_del.set("bizcond", "" + ds_ClntMaster.getCellData(rowPos, "ez112Idx"));
            await $c.sbm.execute(sbm_del);
        }
    }
};

