scwin.savethis = async function() {
    if (ds_ClntMaster.getRowCount() == 0) {
        await $c.win.alert("신규등록 버튼을 눌러서 정보를 입력 해주세요.");
        return false;
    }
    let rowPos = ds_ClntMaster.getRowPosition();
    if (rowPos < 0) return false;
    if (ds_ClntMaster.getCellData(rowPos, "ez106Idx") == "") {
        await $c.win.alert("사업소구분을 선택해주세요.");
        return false;
    } else if (ds_ClntMaster.getCellData(rowPos, "clntCls") == "") {
        await $c.win.alert("분류를 선택해주세요.");
        return false;
    } else if (ds_ClntMaster.getCellData(rowPos, "cmpyKor") == "") {
        await $c.win.alert("상호를 입력해주세요.");
        return false;
    } else if (ds_ClntMaster.getCellData(rowPos, "picNm") == "") {
        await $c.win.alert("담당자명을 입력해주세요.");
        return false;
    } else if ((ds_ClntMaster.getCellData(rowPos, "repstNm") != "") || (ds_ClntMaster.getCellData(rowPos, "bizcond") != "") || (ds_ClntMaster.getCellData(rowPos, "catBusi") != "")) {
        if (ds_ClntMaster.getCellData(rowPos, "crnNo") == "") {
            await $c.win.alert("사업자번호를 입력해주세요.");
            return false;
        }
    }
    scwin.rowPosBeforeSave = rowPos;
    await $c.sbm.execute(sbm_SaveClntMaster);
};

scwin.saveAccount = async function() {
    if (ds_Account.getRowCount() > 0) {
        let lastRow = ds_Account.getRowCount() - 1;
        if (ds_Account.getCellData(lastRow, "bankCd") == "") {
            await $c.win.alert("은행을 선택해주세요.");
        } else if (ds_Account.getCellData(lastRow, "bankAcntNo") == "") {
            await $c.win.alert("계좌번호를 입력해주세요.");
        } else {
            await $c.sbm.execute(sbm_SaveAccount);
        }
    } else {
        await $c.win.alert("신규버튼을 클릭하신 후 데이터를 입력해주세요");
    }
};

