scwin.saveItemFare = async function() {
    if (ds_ItemFare.getRowCount() > 0) {
        if (goods.getValue().trim() == "") {
            await $c.win.alert("품목을 입력해주세요");
            return false;
        }
        if (upr.getValue().trim() == "") {
            await $c.win.alert("단가를 입력해주세요");
            return false;
        }
        if (unitVal_combo.getValue().trim() == "" || unitVal_combo.getValue().trim() == "선택하세요.") {
            await $c.win.alert("단위를 선택해주세요");
            return false;
        }
        if (unit.getValue().trim() == "") {
            await $c.win.alert("단위기준을 입력해주세요");
            return false;
        }
        await $c.sbm.execute(sbm_SaveItemFare);
    } else {
        await $c.win.alert("신규버튼을 클릭하신 후 데이터를 입력해주세요");
    }
};

