};

scwin.RetriveOfClient = async function() {
    let stypeVal = STYPE.getValue();
    let stextVal = STEXT.getValue();
    let allVal = "";
    if (all.getValue() != "") {
        allVal = "1";
    } else {
        allVal = "0";
    }

    if (stypeVal == "0" || stypeVal == "") {
        ds_ClntMaster.removeAll();
        dma_search.set("stype", "0");
        dma_search.set("stext", "");
        dma_search.set("all", allVal);
        await $c.sbm.execute(sbm_RetrieveClntMaster);
    } else if (stypeVal != "0" && stextVal != "") {
        ds_ClntMaster.removeAll();
        dma_search.set("stype", stypeVal);
        dma_search.set("stext", stextVal);
        dma_search.set("all", allVal);
        await $c.sbm.execute(sbm_RetrieveClntMaster);
    } else {
        await $c.win.alert("조회조건이 입력되지 않았습니다.");
    }
};

scwin.calcDivs = function() {
    let rowPos = ds_FixCost.getRowPosition();
    if (rowPos < 0) return;
    // TODO: divsYn checkbox 상태 확인 - body에 해당 컴포넌트 매핑 필요
    let divsYnChecked = ds_FixCost.getCellData(rowPos, "divsYn");
    if (divsYnChecked == "1") {
        ds_FixCost.setCellData(rowPos, "divsYn", "1");
        let levyAmtVal = ds_FixCost.getCellData(rowPos, "levyAmt");
        let levyAmt = parseFloat(levyAmtVal) || 0;
        let divsCnt = 0;
        let levyDdVal = ds_FixCost.getCellData(rowPos, "levyDd");
        let levyDd = parseInt(levyDdVal) || 0;
        let divsAmtCalc = 0;

        let levyStDdVal = ds_FixCost.getCellData(rowPos, "levyStDd");
        let levyStY = parseInt(levyStDdVal.substring(0, 4)) || 0;
        let levyStM = parseInt(levyStDdVal.substring(4, 6)) || 0;
        let levyStD = parseInt(levyStDdVal.substring(6, 8)) || 0;

        let levyEndDdVal = ds_FixCost.getCellData(rowPos, "levyEndDd");
        let levyEndY = parseInt(levyEndDdVal.substring(0, 4)) || 0;
        let levyEndM = parseInt(levyEndDdVal.substring(4, 6)) || 0;
        let levyEndD = parseInt(levyEndDdVal.substring(6, 8)) || 0;

        divsCnt = (levyEndY - levyStY) * 12;
        divsCnt += levyEndM - levyStM - 1;
        if (levyStD < levyDd) { divsCnt++; }
        if (levyEndD > levyDd) { divsCnt++; }

        if (divsCnt > 0) {
            divsAmtCalc = levyAmt / divsCnt;
        }

        ds_FixCost.setCellData(rowPos, "divsAmt", divsAmtCalc);
    } else {
        ds_FixCost.setCellData(rowPos, "divsYn", "0");
        ds_FixCost.setCellData(rowPos, "divsAmt", "");
    }
};

scwin.isBusiNoByValue = async function() {
    let strNo = crnNo.getValue();
    if (strNo != "") {
        let sum = 0;
        let getlist = new Array(10);
        let chkvalue = ["1", "3", "7", "1", "3", "7", "1", "3", "5"];

        for (let i = 0; i < 10; i++) {
            getlist[i] = strNo.substring(i, i + 1);
        }

        for (let i = 0; i < 9; i++) {
            sum += getlist[i] * chkvalue[i];
        }

        sum = sum + parseInt((getlist[8] * 5) / 10);
        let sidliy = sum % 10;
        let sidchk = 0;

        if (sidliy != 0) {
            sidchk = 10 - sidliy;
        } else {
            sidchk = 0;
        }

        if (sidchk != getlist[9]) {
            await $c.win.alert("유효하지 않은 사업자번호입니다.");
            crnNo.setFocus();
        }
    }
    return true;
};

